class Solution {
    public boolean isPossible(int[] nums) {
        int n = nums.length;
        for (int i = 0; i < n - 2; i++) {
            for (int j = i + 1; j < n - 1; j++) {
                if (nums[j] - nums[i] != nums[j+1] - nums[j]) {
                    return false;
                }
            }
        }
        return true;
    }
}
